import{c as t,Q as a,j as i,m as o}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse('{"title":"ACON: Optimizing Context Compression for Long-horizon LLM Agents","description":"","frontmatter":{"title":"ACON: Optimizing Context Compression for Long-horizon LLM Agents","arxiv_id":2510.00615,"authors":"Minki Kang, Wei-Ning Chen, Dongge Han, Huseyin A. Inan, Lukas Wutschitz, Yanzhi Chen, Robert Sim, Saravan Rajmohan","fetched":"2026-05-12T00:00:00.000Z","published":"2025-10-01T00:00:00.000Z","source":"https://arxiv.org/abs/2510.00615","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-05-12-acon-2510-00615.md","filePath":"research/papers/2026-05-12-acon-2510-00615.md","lastUpdated":1779901665000}'),n={name:"research/papers/2026-05-12-acon-2510-00615.md"};function r(s,e,l,c,h,m){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="acon-optimizing-context-compression-for-long-horizon-llm-agents" tabindex="-1">ACON: Optimizing Context Compression for Long-horizon LLM Agents <a class="header-anchor" href="#acon-optimizing-context-compression-for-long-horizon-llm-agents" aria-label="Permalink to &quot;ACON: Optimizing Context Compression for Long-horizon LLM Agents&quot;">​</a></h1><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The paper addresses a critical challenge in deploying language models as agents: managing expanding context lengths from accumulated action and observation histories. The authors propose ACON, a framework that &quot;optimally compresses both environment observations and interaction histories into concise yet informative condensations.&quot;</p><p>The approach employs compression guideline optimization where capable LLMs analyze failures in paired trajectories to refine compression strategies. The authors additionally distill optimized compressors into smaller models to reduce computational overhead.</p><p><strong>Key Results:</strong> The framework achieves &quot;26-54% reduction in memory usage (peak tokens) while largely preserving task performance,&quot; maintains &quot;over 95% of accuracy when distilled into smaller compressors,&quot; and improves smaller language models&#39; performance by &quot;up to 46%&quot; on long-horizon tasks.</p><hr><h2 id="problem-statement" tabindex="-1">Problem Statement <a class="header-anchor" href="#problem-statement" aria-label="Permalink to &quot;Problem Statement&quot;">​</a></h2><p>As LLM agents interact with environments across dozens of steps, accumulated action and observation histories become prohibitively large. This creates dual challenges:</p><ul><li>Elevated computational costs due to transformer scaling with context length</li><li>Diluted attention from irrelevant historical information</li></ul><hr><h2 id="core-contribution" tabindex="-1">Core Contribution <a class="header-anchor" href="#core-contribution" aria-label="Permalink to &quot;Core Contribution&quot;">​</a></h2><p>ACON compresses both interaction histories and environment observations through optimized natural language guidelines rather than parameter fine-tuning. The approach employs &quot;contrastive task feedback&quot;—analyzing failures when compressed context is used versus successes with full context—to iteratively refine compression prompts.</p><hr><h2 id="method-overview" tabindex="-1">Method Overview <a class="header-anchor" href="#method-overview" aria-label="Permalink to &quot;Method Overview&quot;">​</a></h2><p>The framework operates in stages:</p><ol><li><strong>Guideline Optimization</strong>: Uses an LLM to analyze trajectory pairs and generate natural language feedback about what information was lost during compression</li><li><strong>Utility Maximization</strong>: Refines guidelines to preserve task success</li><li><strong>Compression Maximization</strong>: Further optimizes to reduce context while maintaining performance</li><li><strong>Distillation</strong>: Transfers optimized compression capabilities to smaller models</li></ol><hr><h2 id="key-technical-innovation" tabindex="-1">Key Technical Innovation <a class="header-anchor" href="#key-technical-innovation" aria-label="Permalink to &quot;Key Technical Innovation&quot;">​</a></h2><p>Rather than gradient-based optimization requiring parameter updates, the method uses gradient-free prompt optimization compatible with API-based closed-source models, making it deployable without model access.</p><hr><h2 id="experimental-results" tabindex="-1">Experimental Results <a class="header-anchor" href="#experimental-results" aria-label="Permalink to &quot;Experimental Results&quot;">​</a></h2><p>Testing across three benchmarks (AppWorld, OfficeBench, 8-objective QA), ACON achieved:</p><ul><li><strong>Memory efficiency:</strong> 26–54% reduction in peak tokens while largely maintaining task performance</li><li><strong>Distillation effectiveness:</strong> Over 95% performance preservation when distilled into smaller compressors</li><li><strong>Performance improvement:</strong> Improvements of 20-46% for smaller language models operating as agents</li></ul><hr><h2 id="benefits" tabindex="-1">Benefits <a class="header-anchor" href="#benefits" aria-label="Permalink to &quot;Benefits&quot;">​</a></h2><ol><li><strong>Cost Reduction</strong>: Significantly lower token consumption for long-horizon tasks</li><li><strong>Scalability</strong>: Compatible with API-based closed-source models without requiring parameter updates</li><li><strong>Transferability</strong>: Compression strategies distill effectively to smaller models</li><li><strong>Generalization</strong>: Optimized guidelines preserve core task information while removing noise</li></ol><hr><h2 id="availability" tabindex="-1">Availability <a class="header-anchor" href="#availability" aria-label="Permalink to &quot;Availability&quot;">​</a></h2><p>Code is available on GitHub at the Microsoft ACON repository.</p><hr><h2 id="implications" tabindex="-1">Implications <a class="header-anchor" href="#implications" aria-label="Permalink to &quot;Implications&quot;">​</a></h2><p>The work demonstrates that intelligent compression of accumulated agent histories can maintain high performance while dramatically reducing computational overhead. This is particularly valuable for long-horizon multi-step tasks where context accumulation is a primary bottleneck in both cost and attention quality.</p>',32)])])}const u=t(n,[["render",r]]);export{d as __pageData,u as default};
